import Foundation

// Package.swift example
let manifest = """
// swift-tools-version: 5.9
import PackageDescription

let package = Package(
    name: "NetworkingKit",
    platforms: [.iOS(.v15), .macOS(.v12)],
    products: [
        .library(name: "NetworkingKit", targets: ["NetworkingKit"]),
        .library(name: "NetworkingMock", targets: ["NetworkingMock"]),
    ],
    dependencies: [
        .package(url: "https://github.com/Alamofire/Alamofire.git", from: "5.8.0"),
    ],
    targets: [
        .target(
            name: "NetworkingKit",
            dependencies: ["Alamofire"]
        ),
        .target(
            name: "NetworkingMock",
            dependencies: ["NetworkingKit"]
        ),
        .testTarget(
            name: "NetworkingKitTests",
            dependencies: ["NetworkingKit", "NetworkingMock"]
        ),
    ]
)
"""

print(manifest)

// Simple library module
public struct Calculator {
    public init() {}

    public func add(_ a: Int, _ b: Int) -> Int { a + b }
    public func subtract(_ a: Int, _ b: Int) -> Int { a - b }
    public func multiply(_ a: Int, _ b: Int) -> Int { a * b }
    public func divide(_ a: Int, _ b: Int) throws -> Int {
        guard b != 0 else { throw CalculationError.divisionByZero }
        return a / b
    }
}

public enum CalculationError: Error {
    case divisionByZero
}

print("Swift Package Manager allows you to organize and share code as reusable packages")
